mapper.select:
SELECT

FROM OUTBOUND o
WHERE o.`出库单编号` = #{outboundId}

SELECT COUNT(*)
FROM OUTBOUND
WHERE `出库单号` = #{outboundNo}

SELECT o.`出库单编号` AS outboundId, o.`出库单号` AS outboundNo, o.`出库类型` AS outboundType, DATE_FORMAT(o.`出库时间`, '%Y-%m-%d %H:%i:%s') AS outboundTime, o.`关联合同号` AS contractCode, o.`出库去向类型` AS destinationType, o.`出库去向名称` AS destinationName, o.`出库备注` AS remark, o.`状态` AS status, o.`是否锁定` AS locked, e.`员工姓名` AS handlerName, o.`经办人编码` AS handlerId, DATE_FORMAT(o.`审核时间`, '%Y-%m-%d %H:%i:%s') AS auditTime, ae.`员工姓名` AS auditorName, o.`审核意见` AS auditOpinion, c.`企业名称` AS customerName, ( SELECT wi.`废物名称` FROM OUTBOUND_WASTE_ITEM wi WHERE wi.`出库单编号` = o.`出库单编号` ORDER BY wi.`出库危废明细编号` LIMIT 1 ) AS wasteName, ( SELECT wi.`废物代码` FROM OUTBOUND_WASTE_ITEM wi WHERE wi.`出库单编号` = o.`出库单编号` ORDER BY wi.`出库危废明细编号` LIMIT 1 ) AS wasteCode, ( SELECT wi.`库位` FROM OUTBOUND_WASTE_ITEM wi WHERE wi.`出库单编号` = o.`出库单编号` ORDER BY wi.`出库危废明细编号` LIMIT 1 ) AS location, ( SELECT SUM(wi.`出库数量`) FROM OUTBOUND_WASTE_ITEM wi WHERE wi.`出库单编号` = o.`出库单编号` ) AS outboundQty, ( SELECT SUM(wi.`出库辅助数量`) FROM OUTBOUND_WASTE_ITEM wi WHERE wi.`出库单编号` = o.`出库单编号` ) AS outboundAuxQty, ( SELECT wi.`辅助计量单位` FROM OUTBOUND_WASTE_ITEM wi WHERE wi.`出库单编号` = o.`出库单编号` ORDER BY wi.`出库危废明细编号` LIMIT 1 ) AS auxUnit, ( SELECT wi.`扣减前库存重量` FROM OUTBOUND_WASTE_ITEM wi WHERE wi.`出库单编号` = o.`出库单编号` ORDER BY wi.`出库危废明细编号` LIMIT 1 ) AS beforeStockQty, ( SELECT wi.`扣减后库存重量` FROM OUTBOUND_WASTE_ITEM wi WHERE wi.`出库单编号` = o.`出库单编号` ORDER BY wi.`出库危废明细编号` LIMIT 1 ) AS afterStockQty FROM OUTBOUND o LEFT JOIN EMPLOYEE e ON e.`员工编码` = o.`经办人编码` LEFT JOIN EMPLOYEE ae ON ae.`员工编码` = o.`审核人编码` LEFT JOIN CUSTOMER c ON c.`客户编码` = o.`关联客户编号`
AND ( o.`出库单号` LIKE CONCAT('%', #{keyword}, '%') OR o.`关联合同号` LIKE CONCAT('%', #{keyword}, '%') OR c.`企业名称` LIKE CONCAT('%', #{keyword}, '%') )
AND o.`出库类型` = #{outboundType}
AND o.`状态` = #{status}
AND o.`出库去向类型` = #{destinationType}
AND o.`出库时间` >= #{startTime}
AND o.`出库时间` <= #{endTime}
ORDER BY
o.`出库时间` o.`出库单号` o.`状态` o.`出库类型` o.`出库时间`
ASC DESC
ORDER BY o.`出库时间` DESC
